export function headerValue(headers, name) {
  const value = headers[name];
  if (Array.isArray(value)) return value.join(",");
  return value ?? "";
}

export function makeVariantKey(url, varyFields, requestHeaders) {
  const dimensions = varyFields.map(
    (field) => `${field}:${headerValue(requestHeaders, field)}`,
  );
  return JSON.stringify([url, ...dimensions]);
}

