import { makeVariantKey } from "./key.mjs";
import { parseVary } from "./vary.mjs";

export class ResponseCache {
  #entries = new Map();

  put(url, requestHeaders, response) {
    const varyFields = parseVary(response.headers?.vary ?? "");
    const key = makeVariantKey(url, varyFields, requestHeaders);
    this.#entries.set(key, { url, varyFields, response });
  }

  match(url, requestHeaders) {
    for (const entry of this.#entries.values()) {
      if (entry.url !== url) continue;
      const key = makeVariantKey(url, entry.varyFields, requestHeaders);
      if (this.#entries.get(key) === entry) return entry.response;
    }
    return undefined;
  }

  get size() {
    return this.#entries.size;
  }
}

