import test from "node:test";
import assert from "node:assert/strict";
import { ResponseCache } from "../src/cache.mjs";

test("a conventional lowercase language variant is cached", () => {
  const cache = new ResponseCache();
  const response = {
    headers: { vary: "accept-language" },
    body: "bonjour",
  };
  cache.put("/welcome", { "accept-language": "fr" }, response);

  assert.equal(
    cache.match("/welcome", { "accept-language": "fr" }),
    response,
  );
});
